#[test]
fn test_flashrank_latency_top20() {
    let reranker = flashrank_reranker();
    let query = "test query about programming";
    let docs: Vec<&str> = (0..20).map(|_| "sample document text for benchmarking reranker speed").collect();

    // Warmup (3 iterations)
    for _ in 0..3 { reranker.rerank(query, &docs).unwrap(); }

    // Measure (10 iterations)
    let start = Instant::now();
    for _ in 0..10 {
        reranker.rerank(query, &docs).unwrap();
    }
    let avg_ms = start.elapsed().as_millis() as f64 / 10.0;

    info!("FlashRank top-20 reranking: {:.1}ms average", avg_ms);
    // FlashRank nano on CPU should rerank 20 docs in <50ms
    // This is a nano model specifically chosen for speed
    assert!(avg_ms < 50.0, "FlashRank top-20 should be <50ms on CPU, got {:.1}ms", avg_ms);
}

