### Warning Collector
```rust
pub struct WarningCollector {
    warnings: Vec<MessagePanel>,
}

impl WarningCollector {
    pub fn new() -> Self {
        Self { warnings: vec![] }
    }

    pub fn add(&mut self, warning: MessagePanel) {
        self.warnings.push(warning);
    }

    pub fn add_simple(&mut self, title: &str, message: &str) {
        self.warnings.push(MessagePanel::warning(title, message));
    }

    pub fn is_empty(&self) -> bool {
        self.warnings.is_empty()
    }

    pub fn count(&self) -> usize {
        self.warnings.len()
    }

    pub fn render(&self, output: &Output) {
        if self.warnings.is_empty() {
            return;
        }

        if output.is_styled() {
            // Render as a single panel with all warnings
            let theme = &output.theme;
            let mut content = format!(
                "[{} bold]⚠ {} warning(s)[/]\n\n",
                theme.warning,
                self.warnings.len()
            );

            for (i, warning) in self.warnings.iter().enumerate() {
                if i > 0 {
                    content.push_str("\n\n");
                }
                content.push_str(&format!("[bold]{}.[/] {}", i + 1, warning.title));
                if !warning.message.is_empty() {
                    content.push_str(&format!("\n   {}", warning.message));
                }
            }

            let panel = Panel::from_text(&content)
                .border_style(theme.warning);

            output.print_renderable(&panel);
        } else {
            // Plain mode - print all warnings
            eprintln!("[WARN] {} warning(s):", self.warnings.len());
            for (i, warning) in self.warnings.iter().enumerate() {
                eprintln!("  {}. {} - {}", i + 1, warning.title, warning.message);
            }
        }
    }

    pub fn render_individually(&self, output: &Output) {
        for warning in &self.warnings {
            warning.render(output);
        }
    }
}

impl Default for WarningCollector {
    fn default() -> Self {
        Self::new()
    }
}
