+            name,
+            scores[0],
+            scores[2]
+        );
+        assert!(
+            scores[0] > scores[3],
+            "{}: Systems lang doc should beat recipe: {} vs {}",
+            name,
+            scores[0],
+            scores[3]
+        );
+        // Programming doc should beat non-programming
+        assert!(
+            scores[1] > scores[3],
+            "{}: Programming doc should beat recipe: {} vs {}",
+            name,
+            scores[1],
+            scores[3]
