+                || candidates[0].rerank_score.unwrap_or(0.0) >= candidates[1].rerank_score.unwrap_or(0.0),
+            "Rust doc should rank higher for programming query: {:?}",
+            candidates.iter().map(|c| (&c.id, c.rerank_score)).collect::<Vec<_>>()
+        );
+    }
